arguments.argument:
if global.gamePaused=false
{
  moveProg+=1
  if moveProg<=32
  {
    y-=0.5
    if moveProg=32
    {
      xVel=2.5
      if x>=oPlayer1.x
        xVel=2.5
      else
        xVel=-2.5
    }
  }
  else
  {
    yVel+=0.3
    if isCollisionBottom(1)
      yVel=0
    if isCollisionLeft(1)
      xVel*=-1
    if isCollisionRight(1)
      xVel*=-1
    moveTo(xVel,yVel)
  
    if isCollisionSolid()
      y-=2
    if y>room_height+24
      instance_destroy()
  }
}
